VALUES
  ('social-worker-moex-01421', 'social-worker', 'social-worker-moex-109-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '有位研究者想要驗證一種憂鬱治療團體的效果，於是找一群急症期的重度憂鬱患者參與團體，並 以標準化的憂鬱篩檢工具來進行前後測。下列敘述何者錯誤？', '["研究結果前後測無顯著差異，研究者表示該憂鬱治療團體的效果不明顯", "研究結果前後測無顯著差異，研究者宣稱可能因測量工具不靈敏，無法發現該憂鬱治療團體的 效果", "研究結果前後測有顯著差異，批評者認為可能僅是因統計迴歸造成的結果", "研究結果前後測有顯著差異，研究者宣稱其證實該憂鬱治療團體確實有療效"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:09+00:00", "source_pdf_sha1": "3e07f321dfb8", "answer_pdf_sha1": "cf21ad8c6d04", "source_family": "moex-gov-tw", "moex": {"exam_code": "109030", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "109", "exam_name": "109年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
