  ('social-worker-moex-01427', 'social-worker', 'social-worker-moex-109-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '有關研究參與者知情同意書的敘述，下列何者錯誤？', '["內容要包括可能面臨的研究風險", "任何研究的進行都會用到知情同意書", "研究可能造成研究參與者風險愈大者，愈需要取得知情同意書", "研究者必須向研究參與者說明知情同意書，並且研究參與者表示沒有疑問之後，才請他們簽署 知情同意書"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:09+00:00", "source_pdf_sha1": "3e07f321dfb8", "answer_pdf_sha1": "cf21ad8c6d04", "source_family": "moex-gov-tw", "moex": {"exam_code": "109030", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "109", "exam_name": "109年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
